prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?created ?orgId WHERE {
  ?model a bboExt:Model .
  FILTER(tai:normalizedId = "4ac969819d6749d495c4f3be5f4745de")
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    OPTIONAL { ?org tai:organizationId ?orgId . }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?normId ?origId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(
    (BOUND(?normId) && CONTAINS(LCASE(STR(?normId)), LCASE("4ac969"))) ||
    (BOUND(?origId) && CONTAINS(LCASE(STR(?origId)), LCASE("4ac969")))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elemFrom ?fromName ?elemTo ?toName WHERE {
  ?model a bboExt:Model .
  FILTER(tai:originalId = "4ac969819d6749d495c4f3be5f4745de")

  ?def tai:belongsTo ?model .

  ?elemFrom tai:belongsTo+ ?def .
  OPTIONAL { ?elemFrom bbo:name ?fromName . }

  ?elemTo tai:belongsTo+ ?def .
  OPTIONAL { ?elemTo bbo:name ?toName . }

  FILTER(
    (BOUND(?fromName) && CONTAINS(LCASE(STR(?fromName)), LCASE("receive documents")))
  )
  FILTER(
    (BOUND(?toName) && CONTAINS(LCASE(STR(?toName)), LCASE("applicatio")) && CONTAINS(LCASE(STR(?toName)), LCASE("received")))
  )

  FILTER EXISTS {
    ?elemFrom ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?elemTo .
  }
}
LIMIT 25
